18	import tools.jackson.databind.util.IgnorePropertiesUtil;
19	
20	/**
21	 * Builder class used for aggregating deserialization information about
22	 * a property-based POJO, in order to build a {@link ValueDeserializer}
23	 * for deserializing POJO instances.
24	 */
25	public class BeanDeserializerBuilder
26	{
27	    /*
28	    /**********************************************************************
29	    /* Configuration
30	    /**********************************************************************
31	     */
32	
33	    protected final DeserializationConfig _config;
34	
35	    protected final DeserializationContext _context;
36	
37	    /*
38	    /**********************************************************************
39	    /* General information about POJO
40	    /**********************************************************************
41	     */
42	
43	    /**
44	     * Introspected information about POJO for deserializer to handle
45	     */
46	    protected final BeanDescription.Supplier _beanDescRef;
47	
48	    /*
49	    /**********************************************************************
50	    /* Accumulated information about properties
51	    /**********************************************************************
52	     */
53	
54	    /**
55	     * Properties to deserialize collected so far.
56	     */
57	    protected final Map<String, SettableBeanProperty> _properties
58	        = new LinkedHashMap<String, SettableBeanProperty>();
59	
60	    /**
61	     * Parameters of the primary properties-based Creator, if any.
62	     *
63	     * @since 2.18
64	     */
65	    protected SettableBeanProperty[] _propsBasedCreatorParams;
66	
67	    /**
68	     * Value injectors for deserialization
69	     */
70	    protected List<ValueInjector> _injectables;
71	
72	    /**
73	     * Back-reference properties this bean contains (if any)
74	     */
75	    protected HashMap<String, SettableBeanProperty> _backRefProperties;
76	
77	    /**
78	     * Set of names of properties that are recognized but are to be ignored for deserialization
79	     * purposes (meaning no exception is thrown, value is just skipped).
80	     */
81	    protected HashSet<String> _ignorableProps;
82	
83	    /**
84	     * Set of names of properties that are recognized and are set to be included for deserialization
85	     * purposes (null deactivate this, empty includes nothing).
86	     */
87	    protected HashSet<String> _includableProps;
88	
89	    /**
90	     * Object that will handle value instantiation for the bean type.
91	     */
92	    protected ValueInstantiator _valueInstantiator;
93	
94	    /**
95	     * Handler for Object Id values, if Object Ids are enabled for the
96	     * bean type.
97	     */
98	    protected ObjectIdReader _objectIdReader;
99	
100	    /**
101	     * Fallback setter used for handling any properties that are not
102	     * mapped to regular setters. If setter is not null, it will be
103	     * called once for each such property.
104	     */
105	    protected SettableAnyProperty _anySetter;
106	
107	    /**
108	     * Flag that can be set to ignore and skip unknown properties.
109	     * If set, will not throw an exception for unknown properties.
110	     */
111	    protected boolean _ignoreAllUnknown;
112	
113	    /**
114	     * When creating Builder-based deserializers, this indicates
115	     * method to call on builder to finalize value.
116	     */
117	    protected AnnotatedMethod _buildMethod;
118	
119	    /**
120	     * In addition, Builder may have additional configuration
121	     */
122	    protected JsonPOJOBuilder.Value _builderConfig;
123	
124	    /*
125	    /**********************************************************************
126	    /* Life-cycle: construction
127	    /**********************************************************************
128	     */
129	
130	    public BeanDeserializerBuilder(DeserializationContext ctxt,
131	            BeanDescription.Supplier beanDescRef)
132	    {
133	        _beanDescRef = beanDescRef;
134	        _context = ctxt;
135	        _config = ctxt.getConfig();
136	    }
137	
138	    /**
139	     * Copy constructor for sub-classes to use, when constructing
140	     * custom builder instances
141	     */
142	    protected BeanDeserializerBuilder(BeanDeserializerBuilder src)
143	    {
144	        _beanDescRef = src._beanDescRef;
145	        _context = src._context;
146	        _config = src._config;
147	
148	        // let's make copy of properties
149	        _properties.putAll(src._properties);
150	        _injectables = _copy(src._injectables);
151	        _backRefProperties = _copy(src._backRefProperties);
152	        // Hmmh. Should we create defensive copies here? For now, not yet
153	        _ignorableProps = src._ignorableProps;
154	        _includableProps = src._includableProps;
155	        _valueInstantiator = src._valueInstantiator;
156	        _propsBasedCreatorParams = src._propsBasedCreatorParams;
157	        _objectIdReader = src._objectIdReader;
158	
159	        _anySetter = src._anySetter;
160	        _ignoreAllUnknown = src._ignoreAllUnknown;
161	
162	        _buildMethod = src._buildMethod;
163	        _builderConfig = src._builderConfig;
164	    }
165	
166	    private static HashMap<String, SettableBeanProperty> _copy(HashMap<String, SettableBeanProperty> src) {
167	        return (src == null) ? null
168	                : new HashMap<String, SettableBeanProperty>(src);
169	    }
170	
171	    private static <T> List<T> _copy(List<T> src) {
172	        return (src == null) ? null : new ArrayList<T>(src);
173	    }
174	
175	    /*
176	    /**********************************************************************
177	    /* Life-cycle: state modification (adders, setters)
178	    /**********************************************************************
179	     */
180	
181	    /**
182	     * Method for adding a new property or replacing a property.
183	     */
184	    public void addOrReplaceProperty(SettableBeanProperty prop, boolean allowOverride) {
185	        SettableBeanProperty oldProp = _properties.put(prop.getName(), prop);
186	        if ((oldProp != null) && (_propsBasedCreatorParams != null)) {
187	            for (int i = 0, len = _propsBasedCreatorParams.length; i < len; ++i) {
188	                if (_propsBasedCreatorParams[i] == oldProp) {
189	                    _propsBasedCreatorParams[i] = prop;
190	                }
191	            }
192	        }
193	    }
194	
195	    /**
196	     * Method to add a property setter. Will ensure that there is no
197	     * unexpected override; if one is found will throw a
198	     * {@link IllegalArgumentException}.
199	     */
200	    public void addProperty(SettableBeanProperty prop)
201	    {
202	        SettableBeanProperty old =  _properties.put(prop.getName(), prop);
203	        if (old != null && old != prop) { // should never occur...
204	            throw new IllegalArgumentException("Duplicate property '"+prop.getName()
205	            +"' for "+_beanDescRef.getType());
206	        }
207	    }
208	
209	    /**
210	     * Method called to add a property that represents so-called back reference;
211	     * reference that "points back" to object that has forward reference to
212	     * currently built bean.
213	     */
214	    public void  addBackReferenceProperty(String referenceName, SettableBeanProperty prop)
215	    {
216	        if (_backRefProperties == null) {
217	            _backRefProperties = new HashMap<String, SettableBeanProperty>(4);
218	        }
219	        // 15-Sep-2016, tatu: For some reason fixing access at point of `build()` does
220	        //    NOT work (2 failing unit tests). Not 100% clear why, but for now force
221	        //    access set early; unfortunate, but since it works....
222	        if (_config.canOverrideAccessModifiers()) {
223	            try {
224	                prop.fixAccess(_config);
225	            } catch (IllegalArgumentException e) {
226	                _handleBadAccess(e);
227	            }
228	        }
229	        _backRefProperties.put(referenceName, prop);
230	        // 16-Jan-2018, tatu: As per [databind#1878] we may want to leave it as is, to allow
231	        //    population for cases of "wrong direction", traversing parent first
232	        //   If this causes problems should probably instead include in "ignored properties" list
233	        //   Alternatively could also extend annotation to allow/disallow explicit value from input
234	        /*
235	        if (_properties != null) {
236	            _properties.remove(prop.getName());
237	        }
238	        */
239	    }
240	
241	    public void addInjectable(PropertyName propName, JavaType propType,
242	            Annotations contextAnnotations, AnnotatedMember member,
243	            Object valueId, Boolean optional, Boolean useInput)
244	    {
245	        if (_injectables == null) {
246	            _injectables = new ArrayList<>();
247	        }
248	        if ( _config.canOverrideAccessModifiers()) {
249	            try {
250	                member.fixAccess(_config.isEnabled(MapperFeature.OVERRIDE_PUBLIC_ACCESS_MODIFIERS));
251	            } catch (IllegalArgumentException e) {
252	                _handleBadAccess(e);
253	            }
254	        }
255	        _injectables.add(new ValueInjector(propName, propType, member, valueId, optional, useInput));
256	    }
257	
258	    /**
259	     * Method that will add property name as one of properties that can
260	     * be ignored if not recognized.
261	     */
262	    public void addIgnorable(String propName)
263	    {
264	        if (_ignorableProps == null) {
265	            _ignorableProps = new HashSet<>();
266	        }
267	        _ignorableProps.add(propName);
268	    }
269	
270	    /**
271	     * Method that will add property name as one of the properties that will be included.
272	     */
273	    public void addIncludable(String propName)
274	    {
275	        if (_includableProps == null) {
276	            _includableProps = new HashSet<>();
277	        }
278	        _includableProps.add(propName);
279	    }
280	
281	    /**
282	     * Method called by deserializer factory, when a "creator property"
283	     * (something that is passed via constructor- or factory method argument;
284	     * instead of setter or field).
285	     *<p>
286	     * Default implementation does not do anything; we may need to revisit this
287	     * decision if these properties need to be available through accessors.
288	     * For now, however, we just have to ensure that we don't try to resolve
289	     * types that masked setter/field has (see [JACKSON-700] for details).
290	     */
291	    public void addCreatorProperty(SettableBeanProperty prop)
292	    {
293	        addProperty(prop);
294	    }
295	
296	    public void setAnySetter(SettableAnyProperty s)
297	    {
298	        if (_anySetter != null && s != null) {
299	            throw new IllegalStateException("_anySetter already set to non-null");
300	        }
301	        _anySetter = s;
302	    }
303	
304	    public void setIgnoreUnknownProperties(boolean ignore) {
305	        _ignoreAllUnknown = ignore;
306	    }
307	
308	    public void setValueInstantiator(ValueInstantiator inst) {
309	        _valueInstantiator = inst;
310	        _propsBasedCreatorParams = inst.getFromObjectArguments(_config);
311	    }
312	
313	    public void setObjectIdReader(ObjectIdReader r) {
314	        _objectIdReader = r;
315	    }
316	
317	    public void setPOJOBuilder(AnnotatedMethod buildMethod, JsonPOJOBuilder.Value config) {
318	        _buildMethod = buildMethod;
319	        _builderConfig = config;
320	    }
321	
322	    /*
323	    /**********************************************************************
324	    /* Public accessors
325	    /**********************************************************************
326	     */
327	
328	    public JavaType getType() {
329	        return _beanDescRef.getType();
330	    }
331	
332	    /**
333	     * Method that allows accessing all properties that this
334	     * builder currently contains.
335	     *<p>
336	     * Note that properties are returned in order that properties
337	     * are ordered (explictly, or by rule), which is the serialization
338	     * order.
339	     */
340	    public Iterator<SettableBeanProperty> getProperties() {
341	        return _properties.values().iterator();
342	    }
343	
344	    public SettableBeanProperty findProperty(PropertyName propertyName) {
345	        return _properties.get(propertyName.getSimpleName());
346	    }
347	
348	    public boolean hasProperty(PropertyName propertyName) {
349	        return findProperty(propertyName) != null;
350	    }
351	
352	    public SettableBeanProperty removeProperty(PropertyName name) {
353	        return _properties.remove(name.getSimpleName());
354	    }
355	
356	    public SettableAnyProperty getAnySetter() {
357	        return _anySetter;
358	    }
359	
360	    public ValueInstantiator getValueInstantiator() {
361	        return _valueInstantiator;
362	    }
363	
364	    public List<ValueInjector> getInjectables() {
365	        return _injectables;
366	    }
367	
368	    public ObjectIdReader getObjectIdReader() {
369	        return _objectIdReader;
370	    }
371	
372	    public AnnotatedMethod getBuildMethod() {
373	    	return _buildMethod;
374	    }
375	
376	    public JsonPOJOBuilder.Value getBuilderConfig() {
377	        return _builderConfig;
378	    }
379	
380	    public boolean hasIgnorable(String name) {
381	        return IgnorePropertiesUtil.shouldIgnore(name, _ignorableProps, _includableProps);
382	    }
383	
384	    /*
385	    /**********************************************************************
386	    /* Build method(s)
387	    /**********************************************************************
388	     */
389	
390	    /**
391	     * Method for constructing a {@link BeanDeserializer}, given all
392	     * information collected.
393	     */
394	    public ValueDeserializer<?> build()
395	    {
396	        Collection<SettableBeanProperty> props = _properties.values();
397	        _fixAccess(props);
398	        if (_objectIdReader != null) {
399	            // 18-Nov-2012, tatu: May or may not have annotations for id property;
400	            //   but no easy access. But hard to see id property being optional,
401	            //   so let's consider required at this point.
402	            props = _addIdProp(_properties,
403	                    new ObjectIdValueProperty(_objectIdReader, PropertyMetadata.STD_REQUIRED));
404	        }
405	        return new BeanDeserializer(this,
406	                _beanDescRef, _constructPropMap(props), _backRefProperties, _ignorableProps, _ignoreAllUnknown, _includableProps,
407	                _anyViews(props));
408	    }
409	
410	    /**
411	     * Alternate build method used when we must be using some form of
412	     * abstract resolution, usually by using addition Type Id
413	     * ("polymorphic deserialization")
414	     */
415	    public AbstractDeserializer buildAbstract() {
416	        return new AbstractDeserializer(this, _backRefProperties, _properties);
417	    }
418	
419	    /**
420	     * Method for constructing a specialized deserializer that uses
421	     * additional external Builder object during data binding.
422	     */
423	    public ValueDeserializer<?> buildBuilderBased(JavaType valueType, String expBuildMethodName)
424	    {
425	        // First: validation; must have build method that returns compatible type
426	        if (_buildMethod == null) {
427	            // as per [databind#777], allow empty name
428	            if (!expBuildMethodName.isEmpty()) {
429	                _context.reportBadDefinition(_beanDescRef.getType(),
430	                        String.format("Builder class %s does not have build method (name: '%s')",
431	                        ClassUtil.getTypeDescription(_beanDescRef.getType()),
432	                        expBuildMethodName));
433	            }
434	        } else {
435	            // also: type of the method must be compatible
436	            Class<?> rawBuildType = _buildMethod.getRawReturnType();
437	            Class<?> rawValueType = valueType.getRawClass();
438	            if ((rawBuildType != rawValueType)
439	                    && !rawBuildType.isAssignableFrom(rawValueType)
440	                    && !rawValueType.isAssignableFrom(rawBuildType)) {
441	                _context.reportBadDefinition(_beanDescRef.getType(),
442	                        String.format("Build method `%s` has wrong return type (%s), not compatible with POJO type (%s)",
443	                        _buildMethod.getFullName(),
444	                        ClassUtil.getClassDescription(rawBuildType),
445	                        ClassUtil.getTypeDescription(valueType)));
446	            }
447	        }
448	        _fixAccess(_properties.values());
449	        // And if so, we can try building the deserializer
450	        Collection<SettableBeanProperty> props;
451	        if (_objectIdReader != null) {
452	            // May or may not have annotations for id property; but no easy access.
453	            // But hard to see id property being optional, so let's consider required at this point.
454	            props = _addIdProp(_properties,
455	                    new ObjectIdValueProperty(_objectIdReader, PropertyMetadata.STD_REQUIRED));
456	        } else {
457	            props = _properties.values();
458	        }
459	        return createBuilderBasedDeserializer(valueType, _constructPropMap(props),
460	                _anyViews(props));

